module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

reg [7:0] dividend_reg;
reg [7:0] divisor_reg;
reg [15:0] result_reg;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        dividend_reg <= 8'b0;
        divisor_reg <= 8'b0;
        result_reg <= 16'b0;
        res_valid <= 1'b0;
    end else if (opn_valid && res_ready) begin
        dividend_reg <= dividend;
        divisor_reg <= divisor;
        result_reg <= {dividend_reg / divisor_reg, dividend_reg % divisor_reg};
        res_valid <= 1'b1;
    end else begin
        res_valid <= 1'b0;
    end
end

endmodule
